// ================================================================
// sprites.js — Image-Based Sprite Animation System
// Holds real pixel art frames for all 8 classes.
// Add new classes by filling in the DATA block below.
// Patches window.Anim after animations.js loads.
// Descent into Eternity v4.0
// ================================================================

(function () {

// ══════════════════════════════════════════════════════════
//  SPRITE DATA — one entry per class
//  Each class needs: idle_1..N, attack_1..N, damage_1..N
//  Leave a class out and it falls back to pixel blocks.
// ══════════════════════════════════════════════════════════

const SPRITE_DATA = {

        fighter: {
    idle_1: "data:image/png;base64,",
    idle_2: "data:image/png;base64,",
    idle_3: "data:image/png;base64,",
    idle_4: "data:image/png;base64,",
    attack_1: "data:image/png;base64,",
    attack_2: "data:image/png;base64,",
    attack_3: "data:image/png;base64,",
    attack_4: "data:image/png;base64,",
    damage_1: "data:image/png;base64,",
    damage_2: "data:image/png;base64,",
    damage_3: "data:image/png;base64,"
  },

  // wizard:   { ... },
  // rogue:    { ... },
  // paladin:  { ... },
  // ranger:   { ... },
  // barbarian:{ ... },
  // cleric:   { ... },
  // druid:    { ... },

};


// ══════════════════════════════════════════════════════════
//  ANIMATION CONFIG — per class
// ══════════════════════════════════════════════════════════

const ANIM_CONFIG = {

  fighter: {
    // Ping-pong idle: 1→2→3→4→3→2 — slow, natural breathing loop
    idle_seq:       ['idle_1','idle_2','idle_3','idle_4','idle_3','idle_2'],
    idle_timing:    [520, 440, 520, 480, 520, 440],  // ~2.9s full loop
    attack_seq:     ['attack_1','attack_2','attack_3','attack_4'],
    attack_timing:  [120, 110, 110, 400],
    attack_peak_ms: 230,
    damage_seq:     ['damage_1','damage_2','damage_3'],
    damage_timing:  [140, 160, 480],
    combat_size:    180,
    card_size:      90,
  },

  // Add configs here as new classes arrive
  // wizard: { idle_seq: [...], ... },

};


// ══════════════════════════════════════════════════════════
//  INTERNAL HELPERS
// ══════════════════════════════════════════════════════════

function _classId() {
  // G is declared as 'let' in main.js — shared global but NOT on window
  try { return (typeof G !== 'undefined') && G && G.classId; }
  catch(e) { return null; }
}

function _hasSprites(cid) {
  return !!(cid && SPRITE_DATA[cid] && ANIM_CONFIG[cid]);
}

function _setFrame(el, cid, key) {
  if (!el) return;
  const data = SPRITE_DATA[cid] && SPRITE_DATA[cid][key];
  if (!data) return;
  let img = el.querySelector('img.spr-img');
  if (!img) {
    el.innerHTML = '';
    el.style.display    = 'block';
    el.style.background = 'transparent';
    el.style.gridTemplateColumns = '';
    el.style.gap = '';
    img = document.createElement('img');
    img.className = 'spr-img';
    img.style.cssText = [
      'display:block',
      'width:100%',
      'height:100%',
      'object-fit:contain',
      'image-rendering:pixelated',
      'image-rendering:crisp-edges',
      'background:transparent',
    ].join(';');
    el.appendChild(img);
  }
  img.src = data;
}

function _sizeCombatSprite(cid) {
  const el = document.getElementById('playerSprite');
  if (!el) return;
  const sz = (ANIM_CONFIG[cid] && ANIM_CONFIG[cid].combat_size) || 120;
  el.style.width      = sz + 'px';
  el.style.height     = sz + 'px';
  el.style.background = 'transparent';
}


// ══════════════════════════════════════════════════════════
//  IDLE LOOP
// ══════════════════════════════════════════════════════════

let _idleRunning = false;
let _idleTimer   = null;
let _idleIdx     = 0;
let _idleCid     = null;

function _stopIdle() {
  _idleRunning = false;
  _idleCid     = null;
  if (_idleTimer) { clearTimeout(_idleTimer); _idleTimer = null; }
}

function _startIdle(cid) {
  _stopIdle();
  if (!_hasSprites(cid)) return;
  _sizeCombatSprite(cid);
  const el = document.getElementById('playerSprite');
  if (!el) return;
  const cfg = ANIM_CONFIG[cid];
  _idleRunning = true;
  _idleCid     = cid;
  _idleIdx     = 0;
  (function tick() {
    if (!_idleRunning || _idleCid !== cid) return;
    _setFrame(el, cid, cfg.idle_seq[_idleIdx]);
    const delay = cfg.idle_timing[_idleIdx];
    _idleIdx = (_idleIdx + 1) % cfg.idle_seq.length;
    _idleTimer = setTimeout(tick, delay);
  })();
}


// ══════════════════════════════════════════════════════════
//  SEQUENCE PLAYER
// ══════════════════════════════════════════════════════════

function _playSeq(el, cid, seqKey, timingKey, onDone) {
  const cfg = ANIM_CONFIG[cid];
  if (!cfg) { if (onDone) onDone(); return; }
  const seq     = cfg[seqKey];
  const timings = cfg[timingKey];
  let i = 0;
  (function next() {
    if (i >= seq.length) { if (onDone) onDone(); return; }
    _setFrame(el, cid, seq[i]);
    setTimeout(next, timings[i++]);
  })();
}


// ══════════════════════════════════════════════════════════
//  PATCH window.Anim
// ══════════════════════════════════════════════════════════

function _patch() {
  if (!window.Anim) { setTimeout(_patch, 80); return; }

  const _orig = {
    startPlayerIdle: window.Anim.startPlayerIdle.bind(window.Anim),
    stopPlayerIdle:  window.Anim.stopPlayerIdle.bind(window.Anim),
    playerAttack:    window.Anim.playerAttack.bind(window.Anim),
    playerHit:       window.Anim.playerHit.bind(window.Anim),
  };

  window.Anim.startPlayerIdle = function (classId) {
    const cid = classId || _classId();
    if (_hasSprites(cid)) {
      _orig.stopPlayerIdle();
      _startIdle(cid);
    } else {
      _stopIdle();
      _orig.startPlayerIdle(classId);
    }
  };

  window.Anim.stopPlayerIdle = function () {
    _stopIdle();
    _orig.stopPlayerIdle();
  };

  window.Anim.playerAttack = function (onPeak) {
    const cid = _classId();
    if (!_hasSprites(cid)) { _orig.playerAttack(onPeak); return; }
    _stopIdle();
    const el = document.getElementById('playerSprite');
    if (!el) return;
    el.classList.remove('anim-attack', 'anim-idle-' + cid);
    const cfg = ANIM_CONFIG[cid];
    if (onPeak && cfg.attack_peak_ms) setTimeout(onPeak, cfg.attack_peak_ms);
    _playSeq(el, cid, 'attack_seq', 'attack_timing', () => _startIdle(cid));
  };

  window.Anim.playerHit = function () {
    const cid = _classId();
    if (!_hasSprites(cid)) { _orig.playerHit(); return; }
    _stopIdle();
    const el = document.getElementById('playerSprite');
    if (!el) return;
    el.classList.remove('anim-hit', 'anim-idle-' + cid);
    _playSeq(el, cid, 'damage_seq', 'damage_timing', () => _startIdle(cid));
  };
}


// ══════════════════════════════════════════════════════════
//  PATCH renderSprite (combat init + class selection cards)
// ══════════════════════════════════════════════════════════

function _patchRenderSprite() {
  const _origRender = window.renderSprite;
  if (!_origRender) { setTimeout(_patchRenderSprite, 80); return; }

  window.renderSprite = function (data, cellSize, container) {
    if (!container) { _origRender(data, cellSize, container); return; }

    // Combat playerSprite
    if (container.id === 'playerSprite') {
      const cid = _classId();
      if (_hasSprites(cid)) {
        _sizeCombatSprite(cid);
        _setFrame(container, cid, 'idle_1');
        return;
      }
    }

    // Class selection card — cs-sprite-<classId>
    if (container.id && container.id.startsWith('cs-sprite-')) {
      const cid = container.id.replace('cs-sprite-', '');
      if (_hasSprites(cid)) {
        const sz = (ANIM_CONFIG[cid] && ANIM_CONFIG[cid].card_size) || 65;
        container.innerHTML = '';
        container.style.display    = 'block';
        container.style.width      = sz + 'px';
        container.style.height     = sz + 'px';
        container.style.background = 'transparent';
        container.style.gridTemplateColumns = '';
        const img = document.createElement('img');
        img.src = SPRITE_DATA[cid]['idle_1'];
        img.style.cssText = `width:${sz}px;height:${sz}px;object-fit:contain;image-rendering:pixelated;background:transparent;`;
        container.appendChild(img);
        return;
      }
    }

    _origRender(data, cellSize, container);
  };
}


// ══════════════════════════════════════════════════════════
//  BOOT
// ══════════════════════════════════════════════════════════

window.SPRITE_DATA = SPRITE_DATA;
window.ANIM_CONFIG = ANIM_CONFIG;

function _init() {
  _patch();
  _patchRenderSprite();
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', _init);
} else {
  setTimeout(_init, 50);
}

})();
